### useDataTable Hook for Table State Management

Source: https://context7.com/sadmann7/shadcn-table/llms.txt

A client-side hook that provides comprehensive state management for data tables. It handles pagination, sorting, filtering, column visibility, and row selection. The hook accepts data, column definitions, page count, and initial state configurations.

```typescript
"use client";

import { useDataTable } from "@/hooks/use-data-table";
import { type ColumnDef } from "@tanstack/react-table";

interface User {
  id: string;
  name: string;
  email: string;
  role: string;
}

const columns: ColumnDef<User>[] = [
  {
    id: "name",
    accessorKey: "name",
    header: "Name",
    enableColumnFilter: true,
    meta: {
      label: "Name",
      placeholder: "Search names...",
      variant: "text",
    },
  },
  {
    id: "role",
    accessorKey: "role",
    header: "Role",
    enableColumnFilter: true,
    meta: {
      label: "Role",
      variant: "multiSelect",
      options: [
        { label: "Admin", value: "admin" },
        { label: "User", value: "user" },
      ],
    },
  },
];

function UsersTable({ data, pageCount }: { data: User[]; pageCount: number }) {
  const { table } = useDataTable({
    data,
    columns,
    pageCount,
    initialState: {
      pagination: { pageSize: 10 },
      sorting: [{ id: "name", desc: false }],
      columnVisibility: {},
      rowSelection: {},
    },
    enableAdvancedFilter: false,
    debounceMs: 300,
    throttleMs: 50,
    shallow: true,
  });

  return <DataTable table={table} />;
}

```

