### Basic DataTable Component Implementation (TypeScript)

Source: https://context7.com/sadmann7/shadcn-table/llms.txt

Illustrates the fundamental setup of a `DataTable` component, integrating it with a `DataTableToolbar` and using a custom hook `useDataTable` for managing table state. This example assumes the existence of columns definitions and data providers.

```typescript
// Example usage in a page component
"use client";

import { DataTable } from "@/components/data-table/data-table";
import { DataTableToolbar } from "@/components/data-table/data-table-toolbar";
import { useDataTable } from "@/hooks/use-data-table";

function TasksTableClient({ data, pageCount, statusCounts, priorityCounts }) {
  const { table } = useDataTable({
    data,
    columns: getTasksTableColumns({
      statusCounts,
      priorityCounts,
      estimatedHoursRange: { min: 0, max: 120 },
      setRowAction: () => {}, // Placeholder for action
    }),
    pageCount,
    initialState: {
      pagination: { pageSize: 10 },
      sorting: [{ id: "createdAt", desc: true }],
    },
  });

  return (
    <DataTable table={table}>
      <DataTableToolbar table={table} />
    </DataTable>
  );
}

```

