### Next.js Cache API Configuration and Invalidation

Source: https://context7.com/sadmann7/shadcn-table/llms.txt

Demonstrates configuring cache lifecycles and invalidating cache tags using Next.js 15+ cache APIs. It shows how to set cache parameters like revalidate, stale, and expire, and how to use cacheTag for selective invalidation and updateTag for cache updates after mutations. This is crucial for managing data freshness in dynamic tables.

```typescript
"use cache";

import { cacheLife, cacheTag } from "next/cache";
import { updateTag } from "next/cache";

// In query functions
export async function getTasks(input: GetTasksSchema) {
  // Configure cache lifecycle
  cacheLife({ revalidate: 1, stale: 1, expire: 60 });

  // Tag for selective invalidation
  cacheTag("tasks");

  // Query implementation...
}

// In server actions
export async function createTask(input: CreateTaskSchema) {
  // Perform mutation...

  // Invalidate specific cache tags
  updateTag("tasks");
  updateTag("task-status-counts");
  updateTag("task-priority-counts");
}

// Common cache tags:
// - "tasks" - Main tasks data
// - "task-status-counts" - Status aggregations
// - "task-priority-counts" - Priority aggregations
// - "estimated-hours-range" - Hours range data

// Cache lifecycles:
// - getTasks: revalidate: 1s, stale: 1s, expire: 60s
// - Aggregation queries: cacheLife("hours")

```

