### Skater Table Schema Definition (TypeScript)

Source: https://context7.com/sadmann7/shadcn-table/llms.txt

Defines the database schema for the 'skaters' table using Drizzle ORM, intended for live data grid features. It includes fields for skater details, stance, style, status, skating experience, and media, utilizing JSONB for flexible data types like 'tricks' and 'media'.

```typescript
import { integer, jsonb, timestamp, varchar, boolean } from "drizzle-orm/pg-core";
import { pgTable } from "@/db/utils";
import { generateId } from "@/lib/id";
import type { FileCellData } from "@/types/data-grid";

export const skaters = pgTable("skaters", {
  id: varchar("id", { length: 30 })
    .$defaultFn(() => generateId())
    .primaryKey(),
  name: varchar("name", { length: 128 }),
  email: varchar("email", { length: 256 }),
  stance: varchar("stance", {
    length: 30,
    enum: ["regular", "goofy"],
  })
    .notNull()
    .default("regular"),
  style: varchar("style", {
    length: 30,
    enum: ["street", "vert", "park", "freestyle", "all-around"],
  })
    .notNull()
    .default("street"),
  status: varchar("status", {
    length: 30,
    enum: ["amateur", "sponsored", "pro", "legend"],
  })
    .notNull()
    .default("amateur"),
  yearsSkating: integer("years_skating").notNull().default(0),
  startedSkating: timestamp("started_skating"),
  isPro: boolean("is_pro").notNull().default(false),
  tricks: jsonb("tricks").$type<string[]>(),
  media: jsonb("media").$type<Array<FileCellData>>(),
  createdAt: timestamp("created_at").defaultNow().notNull(),
  updatedAt: timestamp("updated_at")
    .default(sql`current_timestamp`)
    .$onUpdate(() => new Date()),
});

export type Skater = typeof skaters.$inferSelect;
export type NewSkater = typeof skaters.$inferInsert;

```
